sql:
SELECT title, release_date, vote_average
FROM films
WHERE vote_average > 7 AND SUBSTR(release_date, 1, 4) < '2015';

external_knowledge:
- 'shining stars of the cinema world' refers to the top directors by average film rating;
- 'highest average acclaim' refers to the highest average rating of films;
- 'bring in the most gold at the box office' refers to the highest total box office revenue.

- "eldest character" refers to the character with the highest age in the film;
- "least experience" refers to the director with the lowest `percent_rank` of experience;
- "seasoned team" refers to the film with the highest average director experience.

- 'Top 10' refers to the highest-ranked films based on box office revenue, average rating, and number of votes;
- 'American films' means films produced in the USA;
- 'Theatrical release' indicates films that were shown in cinemas;
- 'Primarily in English' means English is the main language used in the film.

- "Well-received films" refers to films with an average rating greater than 6.5;
- "Highly relevant keywords" refers to keywords with a relevance score greater than 0.8;
- "The last two decades" refers to the period between 2000 and 2019.

- "Most acclaimed" refers to the director with the highest average rating;
- "More than one film" implies the director has directed at least two films;
- "Average rating above 7.0" indicates the average rating of the director's films must be greater than 7.0.

- 'maestro behind the cinematic masterpiece' refers to the director of the film;
- 'stands tallest in the realm of critically acclaimed films' means the film with the highest average vote score;
- 'elite 10%' refers to the top 10% of films based on their average vote scores.

sql:
SELECT COUNT(film_id) 
FROM spoken_languages 
WHERE iso_639_1 = 'en' AND language_usage = 'primary';

external_knowledge:
- 'shining stars' refers to top directors;
- 'critical acclaim' refers to an average vote of more than 7;
- 'box office success' refers to total revenue greater than 2 billion.

sql:
-- Calculate the overall average vote count for films
SELECT AVG(vote_count) AS overall_average_vote_count
FROM films;
